PREFIX ex: <https://vocab.cfaa.eus/broaching/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?entidad ?tarea ?consumible WHERE {
  { ?entidad ex:requiereMantenimiento ?tarea . ?tarea ex:requiereConsumible ?consumible . }
  UNION
  { ?entidad ex:requiereConsumible ?consumible . BIND(?entidad AS ?tarea) }
}

