SELECT ?entidad ?componente ?esquema WHERE {
  { ?entidad ex:tieneComponente ?componente . ?componente ex:detalladoEnEsquema ?esquema . }
  UNION
  { ?componente ex:detalladoEnEsquema ?esquema . BIND(?componente AS ?entidad) }
}

