SELECT DISTINCT ?cnc ?controlado ?alarma WHERE {
  ?cnc a ex:Sistema ;
       ex:controla ?controlado .
  ?controlado ex:activaAlarma ?alarma .
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT ?alarma WHERE {
  ?alarma a ex:Alarma .
  FILTER NOT EXISTS {
    ?fallo a ex:DiagnosticoFallo .
    ?tarea ex:solucionaFallo ?fallo .
    ?alarma ex:alarmaActivadaPor ?entidad .
  }
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT ?tarea WHERE {
  ?tarea a ex:TareaMantenimiento .
  FILTER NOT EXISTS { ?tarea ex:tieneFrecuencia ?f }
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT ?tarea WHERE {
  ?tarea a ex:TareaMantenimiento .
  FILTER NOT EXISTS { ?tarea ex:ejecutadoPor ?p }
  FILTER NOT EXISTS { ?tarea ex:habilitadoPor ?p }
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT ?aviso WHERE {
  ?aviso a ex:AvisoSeguridad .
  FILTER NOT EXISTS { ?aviso ex:mitigaRiesgo ?riesgo }
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT (COUNT(DISTINCT ?alarma) AS ?totalAlarmas) WHERE {
  ?sistema ex:activaAlarma ?alarma .
  ?alarma a ex:Alarma .
}

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
SELECT ?sistema (COUNT(DISTINCT ?tarea) AS ?numTareas) WHERE {
  ?sistema a ex:Sistema ;
           ex:requiereMantenimiento ?tarea .
} GROUP BY ?sistema ORDER BY DESC(?numTareas)

PREFIX ex: <https://vocab.cfaa.eus/broaching/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?parametro ?id (COUNT(DISTINCT ?entidad) AS ?numMonitores) WHERE {
  ?entidad ex:monitoreaParametro ?parametro .
  OPTIONAL { ?parametro ex:identificador ?id }
} GROUP BY ?parametro ?id ORDER BY DESC(?numMonitores) LIMIT 10
